const stdout = $('Poll Progress').first().json.stdout || '';
const trigger = $('Normalize Input').first().json;
const issueId = trigger.issueId || 'unknown';
const targetRoom = trigger.targetRoom || '!PVkZvHgyrtBVEbgpRt:matrix.example.net';
const startTime = trigger.startTime || Date.now();

const aliveMatch = stdout.match(/ALIVE:(true|false|grace)/);
const aliveVal = aliveMatch ? aliveMatch[1] : 'false';
const shouldContinue = aliveVal === 'true' || aliveVal === 'grace';

const linesMatch = stdout.match(/LINES_START\n([\s\S]*?)\nLINES_END/);
const rawLines = linesMatch ? linesMatch[1].trim() : '';

// Strip common prefixes from bash commands to show the meaningful part
function cleanBashCmd(cmd) {
  let c = cmd;
  c = c.replace(/^source\s+\S+\.env\s*&&\s*/g, '');
  c = c.replace(/^\. \S+\.env\s*&&\s*/g, '');
  c = c.replace(/^cd\s+\S+\s*&&\s*/g, '');
  c = c.replace(/^PATH=\S+\s+/g, '');
  c = c.replace(/^export\s+\S+\s*&&\s*/g, '');
  c = c.replace(/^export\s+\S+\s+\S+\s*&&\s*/g, '');
  c = c.replace(/\/home\/app-user\/gitlab\/products\/cubeos\//g, '');
  c = c.replace(/\/home\/app-user\/gitlab\/infrastructure\/nl\/production\//g, 'iac/');
  c = c.replace(/\/home\/app-user\/gitlab\//g, '~/');
  c = c.replace(/\/home\/app-user\//g, '~/');
  return c.substring(0, 80);
}

function shortPath(p) {
  return p.replace(/\/home\/app-user\/gitlab\/products\/cubeos\//g, '')
          .replace(/\/home\/app-user\/gitlab\/infrastructure\/nl\/production\//g, 'iac/')
          .replace(/\/home\/app-user\/gitlab\//g, '~/')
          .replace(/\/home\/app-user\//g, '~/');
}

// Clean up MCP tool names for human readability
function cleanToolName(name) {
  if (!name.startsWith('mcp__')) return name;
  const parts = name.replace(/^mcp__/, '').split('__');
  const server = parts[0] || '';
  const action = parts.slice(1).join(' ').replace(/_/g, ' ');
  const serverNames = {
    'proxmox': 'Proxmox', 'youtrack': 'YouTrack', 'netbox': 'NetBox',
    'kubernetes': 'K8s', 'n8n-mcp': 'n8n', 'codegraph': 'CodeGraph',
    'opentofu': 'OpenTofu', 'tfmcp': 'Terraform', 'gitlab': 'GitLab'
  };
  return (serverNames[server] || server) + ': ' + action;
}

const tools = [];
if (rawLines) {
  for (const line of rawLines.split('\n')) {
    if (!line.trim()) continue;
    try {
      const obj = JSON.parse(line.trim());
      if (obj.type === 'assistant' && obj.message && obj.message.content) {
        for (const c of obj.message.content) {
          if (c.type === 'tool_use') {
            const name = c.name || '?';
            const inp = c.input || {};
            let detail = '';
            if (name === 'Bash' && inp.command) {
              detail = cleanBashCmd(inp.command);
            } else if (inp.pattern) {
              detail = shortPath(inp.pattern);
            } else if (inp.file_path) {
              detail = shortPath(inp.file_path).split('/').pop();
            } else if (inp.query) {
              detail = inp.query.substring(0, 60);
            } else if (inp.command) {
              detail = cleanBashCmd(inp.command);
            }
            const displayName = cleanToolName(name);
            tools.push(displayName + (detail ? ' ' + detail : ''));
          }
        }
      }
    } catch (e) { /* skip non-JSON lines */ }
  }
}

// Deduplicate consecutive identical tool lines
const deduped = [];
for (const t of tools) {
  if (deduped.length === 0 || deduped[deduped.length - 1].text !== t) {
    deduped.push({ text: t, count: 1 });
  } else {
    deduped[deduped.length - 1].count++;
  }
}

const elapsed = Math.floor((Date.now() - startTime) / 1000);
const mins = Math.floor(elapsed / 60);
const secs = elapsed % 60;
const recentDeduped = deduped.slice(-6);

// Timestamp in HH:MM CET
const now = new Date();
const ts = now.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Amsterdam' });

let shouldPost = recentDeduped.length > 0;
let body = '';
let htmlBody = '';
if (shouldPost) {
  const toolLines = recentDeduped.map(d => '  ' + d.text + (d.count > 1 ? ' (x' + d.count + ')' : '')).join('\n');
  body = ts + ' [' + issueId + '] Working... (' + mins + 'm' + secs + 's)\n' + toolLines;
  const htmlTools = recentDeduped.map(d => {
    const escaped = (d.text + (d.count > 1 ? ' <i>(x' + d.count + ')</i>' : '')).replace(/</g,'&lt;').replace(/>/g,'&gt;');
    return '&nbsp;&nbsp;' + escaped.replace('&lt;i&gt;', '<i>').replace('&lt;/i&gt;', '</i>');
  }).join('<br>');
  htmlBody = '<code>' + ts + '</code> <b>[' + issueId + ']</b> Working... (' + mins + 'm' + secs + 's)<br>' + htmlTools;
}

return [{ json: { shouldPost, shouldContinue, targetRoom, body, htmlBody } }];

// Works for both webhook (data in .body) and execute-workflow trigger (data at root)
const d = $input.first().json;
const src = d.body && d.body.pid ? d.body : d;
return [{ json: { pid: src.pid || 0, logFile: src.logFile || '', issueId: src.issueId || 'unknown', targetRoom: src.targetRoom || '!PVkZvHgyrtBVEbgpRt:matrix.example.net', startTime: src.startTime || Date.now() } }];

